/*
 * COMP 321 Project 6: Web Proxy
 *
 * This program implements a multithreaded HTTP proxy.
 *
 * Submission prepared in this workspace; student name and NetID were not
 * provided in the prompt.
 */

#include <assert.h>
#include <ctype.h>
#include <errno.h>

#include "csapp.h"

#define NTHREADS 8
#define SBUFSIZE 32
#define MAX_REQUEST_LINE 65536
#define MAX_HEADER_LINE 65536

typedef struct {
	int *buf;
	int n;
	int front;
	int rear;
	int count;
	pthread_mutex_t mutex;
	pthread_cond_t not_empty;
	pthread_cond_t not_full;
} sbuf_t;

static FILE *log_file;
static pthread_mutex_t log_mutex = PTHREAD_MUTEX_INITIALIZER;
static sbuf_t conn_queue;

static void	client_error(int fd, const char *cause, int err_num,
		    const char *short_msg, const char *long_msg);
static char    *create_log_entry(const struct sockaddr_in *sockaddr,
		    const char *uri, int size);
static int	parse_uri(const char *uri, char **hostnamep, char **portp,
		    char **pathnamep);

static void	sbuf_init(sbuf_t *sp, int n);
static void	sbuf_insert(sbuf_t *sp, int item);
static int	sbuf_remove(sbuf_t *sp);
static void	*worker(void *arg);
static void	handle_client(int connfd, const struct sockaddr_in *clientaddr);
static int	open_clientfd_safe(const char *hostname, const char *port);
static ssize_t	rio_readlineb_full(rio_t *rp, char **linep, size_t limit);
static int	append_bytes(char **bufp, size_t *lenp, size_t *capp,
		    const char *src, size_t n);
static int	parse_request_line(char *line, char **methodp, char **urip,
		    char **versionp);
static char	*trim_header_value(char *value);
static int	parse_host_header(const char *host_header, char **hostnamep,
		    char **portp);
static int	should_skip_header(const char *line);
static void	write_log_entry(const struct sockaddr_in *clientaddr,
		    const char *uri, int size);

/*
 * Requires:
 *   The program must be invoked with exactly one command-line argument that
 *   names the port on which the proxy should listen.
 *
 * Effects:
 *   Opens the listening socket and the access log, initializes the bounded
 *   buffer used to hand off accepted connections, creates a fixed pool of
 *   worker threads, and then accepts client connections forever.
 */
int
main(int argc, char **argv)
{
	pthread_t tid;
	int listenfd;
	struct sockaddr_storage clientaddr;
	socklen_t clientlen;
	int connfd;

	if (argc != 2) {
		fprintf(stderr, "Usage: %s <port number>\n", argv[0]);
		exit(0);
	}

	Signal(SIGPIPE, SIG_IGN);

	listenfd = open_listenfd(argv[1]);
	if (listenfd < 0) {
		fprintf(stderr, "Unable to listen on port %s\n", argv[1]);
		exit(1);
	}

	log_file = fopen("proxy.log", "w");
	if (log_file == NULL) {
		fprintf(stderr, "Unable to open proxy.log: %s\n", strerror(errno));
		close(listenfd);
		exit(1);
	}

	sbuf_init(&conn_queue, SBUFSIZE);
	for (int i = 0; i < NTHREADS; i++)
		Pthread_create(&tid, NULL, worker, NULL);

	for (;;) {
		clientlen = sizeof(clientaddr);
		connfd = accept(listenfd, (SA *)&clientaddr, &clientlen);
		if (connfd < 0) {
			if (errno == EINTR)
				continue;
			continue;
		}
		sbuf_insert(&conn_queue, connfd);
	}
}

static void
sbuf_init(sbuf_t *sp, int n)
{
	sp->buf = Malloc((size_t)n * sizeof(int));
	sp->n = n;
	sp->front = 0;
	sp->rear = 0;
	sp->count = 0;
	pthread_mutex_init(&sp->mutex, NULL);
	pthread_cond_init(&sp->not_empty, NULL);
	pthread_cond_init(&sp->not_full, NULL);
}

static void
sbuf_insert(sbuf_t *sp, int item)
{
	pthread_mutex_lock(&sp->mutex);
	while (sp->count == sp->n)
		pthread_cond_wait(&sp->not_full, &sp->mutex);
	sp->buf[sp->rear] = item;
	sp->rear = (sp->rear + 1) % sp->n;
	sp->count++;
	pthread_cond_signal(&sp->not_empty);
	pthread_mutex_unlock(&sp->mutex);
}

static int
sbuf_remove(sbuf_t *sp)
{
	int item;

	pthread_mutex_lock(&sp->mutex);
	while (sp->count == 0)
		pthread_cond_wait(&sp->not_empty, &sp->mutex);
	item = sp->buf[sp->front];
	sp->front = (sp->front + 1) % sp->n;
	sp->count--;
	pthread_cond_signal(&sp->not_full);
	pthread_mutex_unlock(&sp->mutex);
	return (item);
}

static void *
worker(void *arg)
{
	int connfd;
	struct sockaddr_in clientaddr;
	socklen_t clientlen;

	(void)arg;
	Pthread_detach(Pthread_self());

	for (;;) {
		connfd = sbuf_remove(&conn_queue);
		clientlen = sizeof(clientaddr);
		if (getpeername(connfd, (SA *)&clientaddr, &clientlen) == 0)
			handle_client(connfd, &clientaddr);
		else {
			memset(&clientaddr, 0, sizeof(clientaddr));
			handle_client(connfd, &clientaddr);
		}
		close(connfd);
	}

	return (NULL);
}

static void
handle_client(int connfd, const struct sockaddr_in *clientaddr)
{
	rio_t client_rio, server_rio;
	char *request_line = NULL, *line = NULL;
	char *method = NULL, *uri = NULL, *version = NULL;
	char *hostname = NULL, *port = NULL, *pathname = NULL;
	char *host_header = NULL, *forward_headers = NULL, *request_buf = NULL;
	char *log_uri = NULL;
	size_t headers_len = 0, headers_cap = 0, request_len = 0, request_cap = 0;
	int serverfd = -1;
	int saw_host = 0;
	int response_size = 0;
	int absolute_uri = 0;
	int should_log = 0;

	rio_readinitb(&client_rio, connfd);
	if (rio_readlineb_full(&client_rio, &request_line, MAX_REQUEST_LINE) <= 0)
		goto cleanup;

	if (parse_request_line(request_line, &method, &uri, &version) < 0) {
		client_error(connfd, "Malformed request line", 400, "Bad Request",
		    "Proxy could not parse the request line");
		goto cleanup;
	}

	if (strcasecmp(method, "GET") != 0) {
		client_error(connfd, method, 501, "Not Implemented",
		    "Proxy only implements the GET method");
		goto cleanup;
	}

	if (strcmp(version, "HTTP/1.0") != 0 && strcmp(version, "HTTP/1.1") != 0) {
		client_error(connfd, version, 400, "Bad Request",
		    "Proxy only accepts HTTP/1.0 and HTTP/1.1 requests");
		goto cleanup;
	}

	while (1) {
		ssize_t n = rio_readlineb_full(&client_rio, &line, MAX_HEADER_LINE);
		if (n < 0) {
			client_error(connfd, "Malformed headers", 400, "Bad Request",
			    "Proxy could not read the request headers");
			goto cleanup;
		}
		if (n == 0)
			goto cleanup;
		if (strcmp(line, "\r\n") == 0 || strcmp(line, "\n") == 0)
			break;

		if (strncasecmp(line, "Host:", 5) == 0) {
			free(host_header);
			host_header = strdup(trim_header_value(line + 5));
			if (host_header == NULL)
				unix_error("strdup error");
			saw_host = 1;
		}

		if (should_skip_header(line))
			continue;
		if (append_bytes(&forward_headers, &headers_len, &headers_cap, line,
			strlen(line)) < 0) {
			client_error(connfd, "Request headers too large", 400,
			    "Bad Request", "Proxy could not buffer the request headers");
			goto cleanup;
		}
	}

	if (strncasecmp(uri, "http://", 7) == 0) {
		absolute_uri = 1;
		if (parse_uri(uri, &hostname, &port, &pathname) < 0) {
			client_error(connfd, uri, 400, "Bad Request",
			    "Proxy could not parse the URI");
			goto cleanup;
		}
	} else if (uri[0] == '/') {
		if (!saw_host) {
			client_error(connfd, uri, 400, "Bad Request",
			    "Relative URI requires a Host header");
			goto cleanup;
		}
		if (parse_host_header(host_header, &hostname, &port) < 0) {
			client_error(connfd, host_header, 400, "Bad Request",
			    "Proxy could not parse the Host header");
			goto cleanup;
		}
		pathname = strdup(uri);
		if (pathname == NULL)
			unix_error("strdup error");
	} else {
		client_error(connfd, uri, 400, "Bad Request",
		    "Proxy requires an absolute URI or absolute path");
		goto cleanup;
	}

	if (!saw_host) {
		size_t needed = strlen(hostname) + strlen(port) + 2;
		host_header = Malloc(needed);
		if (strcmp(port, "80") == 0)
			snprintf(host_header, needed, "%s", hostname);
		else
			snprintf(host_header, needed, "%s:%s", hostname, port);
	}

	if (absolute_uri) {
		log_uri = strdup(uri);
		if (log_uri == NULL)
			unix_error("strdup error");
	} else {
		size_t needed = strlen("http://") + strlen(host_header) +
		    strlen(pathname) + 1;
		log_uri = Malloc(needed);
		snprintf(log_uri, needed, "http://%s%s", host_header, pathname);
	}

	if (append_bytes(&request_buf, &request_len, &request_cap, "GET ", 4) < 0 ||
	    append_bytes(&request_buf, &request_len, &request_cap, pathname,
		strlen(pathname)) < 0 ||
	    append_bytes(&request_buf, &request_len, &request_cap,
		" HTTP/1.0\r\n", 11) < 0 ||
	    append_bytes(&request_buf, &request_len, &request_cap, "Host: ", 6) < 0 ||
	    append_bytes(&request_buf, &request_len, &request_cap, host_header,
		strlen(host_header)) < 0 ||
	    append_bytes(&request_buf, &request_len, &request_cap, "\r\n", 2) < 0 ||
	    append_bytes(&request_buf, &request_len, &request_cap,
		"Connection: close\r\n", 19) < 0 ||
	    append_bytes(&request_buf, &request_len, &request_cap,
		"Proxy-Connection: close\r\n", 25) < 0 ||
	    append_bytes(&request_buf, &request_len, &request_cap, forward_headers,
		headers_len) < 0 ||
	    append_bytes(&request_buf, &request_len, &request_cap, "\r\n", 2) < 0) {
		client_error(connfd, "Request too large", 400, "Bad Request",
		    "Proxy could not buffer the outbound request");
		goto cleanup;
	}

	serverfd = open_clientfd_safe(hostname, port);
	if (serverfd < 0) {
		client_error(connfd, hostname, 502, "Bad Gateway",
		    "Proxy could not connect to the end server");
		goto cleanup;
	}

	if (rio_writen(serverfd, request_buf, request_len) < 0)
		goto cleanup;

	rio_readinitb(&server_rio, serverfd);
	while (1) {
		char buf[MAXBUF];
		ssize_t n = rio_readnb(&server_rio, buf, sizeof(buf));

		if (n < 0) {
			if (response_size > 0)
				should_log = 1;
			goto cleanup;
		}
		if (n == 0)
			break;
		response_size += (int)n;
		if (rio_writen(connfd, buf, (size_t)n) < 0)
			break;
	}

	should_log = 1;

cleanup:
	if (should_log)
		write_log_entry(clientaddr, log_uri, response_size);
	free(request_line);
	free(line);
	free(method);
	free(uri);
	free(version);
	free(hostname);
	free(port);
	free(pathname);
	free(host_header);
	free(forward_headers);
	free(request_buf);
	free(log_uri);
	if (serverfd >= 0)
		close(serverfd);
}

static int
open_clientfd_safe(const char *hostname, const char *port)
{
	struct addrinfo hints, *listp, *p;
	int clientfd = -1;
	int rc;

	memset(&hints, 0, sizeof(hints));
	hints.ai_socktype = SOCK_STREAM;
	hints.ai_flags = AI_NUMERICSERV | AI_ADDRCONFIG;

	rc = getaddrinfo(hostname, port, &hints, &listp);
	if (rc != 0)
		return (-1);

	for (p = listp; p != NULL; p = p->ai_next) {
		clientfd = socket(p->ai_family, p->ai_socktype, p->ai_protocol);
		if (clientfd < 0)
			continue;
		if (connect(clientfd, p->ai_addr, p->ai_addrlen) == 0)
			break;
		close(clientfd);
		clientfd = -1;
	}

	freeaddrinfo(listp);
	return (clientfd);
}

static ssize_t
rio_readlineb_full(rio_t *rp, char **linep, size_t limit)
{
	char chunk[MAXLINE];
	char *buf = NULL;
	size_t len = 0, cap = 0;
	ssize_t n;

	while (1) {
		n = rio_readlineb(rp, chunk, sizeof(chunk));
		if (n <= 0) {
			free(buf);
			return (n);
		}
		if (len + (size_t)n + 1 > limit) {
			free(buf);
			return (-1);
		}
		if (append_bytes(&buf, &len, &cap, chunk, (size_t)n) < 0) {
			free(buf);
			return (-1);
		}
		if (chunk[n - 1] == '\n')
			break;
	}

	*linep = buf;
	return ((ssize_t)len);
}

static int
append_bytes(char **bufp, size_t *lenp, size_t *capp, const char *src, size_t n)
{
	size_t newcap;
	char *newbuf;

	if (n == 0)
		return (0);
	if (*bufp == NULL) {
		newcap = MAXBUF;
		while (newcap < n + 1)
			newcap *= 2;
		*bufp = Malloc(newcap);
		(*bufp)[0] = '\0';
		*capp = newcap;
	}
	while (*lenp + n + 1 > *capp) {
		newcap = (*capp) * 2;
		newbuf = Realloc(*bufp, newcap);
		*bufp = newbuf;
		*capp = newcap;
	}
	memcpy(*bufp + *lenp, src, n);
	*lenp += n;
	(*bufp)[*lenp] = '\0';
	return (0);
}

static int
parse_request_line(char *line, char **methodp, char **urip, char **versionp)
{
	char *saveptr;
	char *method, *uri, *version, *extra;

	method = strtok_r(line, " \t\r\n", &saveptr);
	uri = strtok_r(NULL, " \t\r\n", &saveptr);
	version = strtok_r(NULL, " \t\r\n", &saveptr);
	extra = strtok_r(NULL, " \t\r\n", &saveptr);
	if (method == NULL || uri == NULL || version == NULL || extra != NULL)
		return (-1);

	*methodp = strdup(method);
	*urip = strdup(uri);
	*versionp = strdup(version);
	if (*methodp == NULL || *urip == NULL || *versionp == NULL)
		unix_error("strdup error");
	return (0);
}

static char *
trim_header_value(char *value)
{
	char *start = value;
	char *end;

	while (*start != '\0' && isspace((unsigned char)*start))
		start++;
	end = start + strlen(start);
	while (end > start && isspace((unsigned char)end[-1]))
		end--;
	*end = '\0';
	return (start);
}

static int
parse_host_header(const char *host_header, char **hostnamep, char **portp)
{
	const char *colon;
	size_t host_len;

	if (host_header[0] == '\0')
		return (-1);
	if (host_header[0] == '[')
		return (-1);

	colon = strchr(host_header, ':');
	if (colon == NULL) {
		*hostnamep = strdup(host_header);
		*portp = strdup("80");
	} else {
		host_len = (size_t)(colon - host_header);
		*hostnamep = Malloc(host_len + 1);
		memcpy(*hostnamep, host_header, host_len);
		(*hostnamep)[host_len] = '\0';
		*portp = strdup(colon + 1);
	}
	if (*hostnamep == NULL || *portp == NULL)
		unix_error("host header allocation error");
	return (**hostnamep == '\0' || **portp == '\0') ? -1 : 0;
}

static int
should_skip_header(const char *line)
{
	return (strncasecmp(line, "Host:", 5) == 0 ||
	    strncasecmp(line, "Connection:", 11) == 0 ||
	    strncasecmp(line, "Proxy-Connection:", 17) == 0 ||
	    strncasecmp(line, "Keep-Alive:", 11) == 0);
}

static void
write_log_entry(const struct sockaddr_in *clientaddr, const char *uri, int size)
{
	char *entry = create_log_entry(clientaddr, uri, size);

	pthread_mutex_lock(&log_mutex);
	fprintf(log_file, "%s\n", entry);
	fflush(log_file);
	pthread_mutex_unlock(&log_mutex);
	free(entry);
}

/*
 * Requires:
 *   The parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Given a URI from an HTTP proxy GET request (i.e., a URL), extract the
 *   host name, port, and path name.  Create strings containing the host name,
 *   port, and path name, and return them through the parameters "hostnamep",
 *   "portp", "pathnamep", respectively.  (The caller must free the memory
 *   storing these strings.)  Return -1 if there are any problems and 0
 *   otherwise.
 */
static int
parse_uri(const char *uri, char **hostnamep, char **portp, char **pathnamep)
{
	const char *pathname_begin, *port_begin, *port_end;

	if (strncasecmp(uri, "http://", 7) != 0)
		return (-1);

	/* Extract the host name. */
	const char *host_begin = uri + 7;
	const char *host_end = strpbrk(host_begin, ":/ \r\n");
	if (host_end == NULL)
		host_end = host_begin + strlen(host_begin);
	int len = host_end - host_begin;
	char *hostname = Malloc(len + 1);
	strncpy(hostname, host_begin, len);
	hostname[len] = '\0';
	*hostnamep = hostname;

	/* Look for a port number.  If none is found, use port 80. */
	if (*host_end == ':') {
		port_begin = host_end + 1;
		port_end = strpbrk(port_begin, "/ \r\n");
		if (port_end == NULL)
			port_end = port_begin + strlen(port_begin);
		len = port_end - port_begin;
	} else {
		port_begin = "80";
		port_end = host_end;
		len = 2;
	}
	char *port = Malloc(len + 1);
	strncpy(port, port_begin, len);
	port[len] = '\0';
	*portp = port;

	/* Extract the path. */
	if (*port_end == '/') {
		pathname_begin = port_end;
		const char *pathname_end = strpbrk(pathname_begin, " \r\n");
		if (pathname_end == NULL)
			pathname_end = pathname_begin + strlen(pathname_begin);
		len = pathname_end - pathname_begin;
	} else {
		pathname_begin = "/";
		len = 1;
	}
	char *pathname = Malloc(len + 1);
	strncpy(pathname, pathname_begin, len);
	pathname[len] = '\0';
	*pathnamep = pathname;

	return (0);
}

/*
 * Requires:
 *   The parameter "sockaddr" must point to a valid sockaddr_in structure.  The
 *   parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Returns a string containing a properly formatted log entry.  This log
 *   entry is based upon the socket address of the requesting client
 *   ("sockaddr"), the URI from the request ("uri"), and the size in bytes of
 *   the response from the server ("size").
 */
static char *
create_log_entry(const struct sockaddr_in *sockaddr, const char *uri, int size)
{
	struct tm result;

	/*
	 * Create a large enough array of characters to store a log entry.
	 * Although the length of the URI can exceed MAXLINE, the combined
	 * lengths of the other fields and separators cannot.
	 */
	const size_t log_maxlen = MAXLINE + strlen(uri);
	char *const log_str = Malloc(log_maxlen + 1);

	/* Get a formatted time string. */
	time_t now = time(NULL);
	int log_strlen = strftime(log_str, MAXLINE, "%a %d %b %Y %H:%M:%S %Z: ",
	    localtime_r(&now, &result));

	/*
	 * Convert the IP address in network byte order to dotted decimal
	 * form.
	 */
	Inet_ntop(AF_INET, &sockaddr->sin_addr, &log_str[log_strlen],
	    INET_ADDRSTRLEN);
	log_strlen += strlen(&log_str[log_strlen]);

	/*
	 * Assert that the time and IP address fields occupy less than half of
	 * the space that is reserved for the non-URI fields.
	 */
	assert(log_strlen < MAXLINE / 2);

	/*
	 * Add the URI and response size onto the end of the log entry.
	 */
	snprintf(&log_str[log_strlen], log_maxlen - log_strlen, " %s %d", uri,
	    size);

	return (log_str);
}

/*
 * Requires:
 *   The parameter "fd" must be an open socket that is connected to the client.
 *   The parameters "cause", "short_msg", and "long_msg" must point to properly
 *   NUL-terminated strings that describe the reason why the HTTP transaction
 *   failed.  The string "short_msg" may not exceed 32 characters in length,
 *   and the string "long_msg" may not exceed 80 characters in length.
 *
 * Effects:
 *   Constructs an HTML page describing the reason why the HTTP transaction
 *   failed, and writes an HTTP/1.0 response containing that page as the
 *   content.  The cause appearing in the HTML page is truncated if the
 *   string "cause" exceeds 2048 characters in length.
 */
static void
client_error(int fd, const char *cause, int err_num, const char *short_msg,
    const char *long_msg)
{
	char body[MAXBUF], headers[MAXBUF], truncated_cause[2049];

	assert(strlen(short_msg) <= 32);
	assert(strlen(long_msg) <= 80);
	/* Ensure that "body" is much larger than "truncated_cause". */
	assert(sizeof(truncated_cause) < MAXBUF / 2);

	/*
	 * Create a truncated "cause" string so that the response body will not
	 * exceed MAXBUF.
	 */
	strncpy(truncated_cause, cause, sizeof(truncated_cause) - 1);
	truncated_cause[sizeof(truncated_cause) - 1] = '\0';

	/* Build the HTTP response body. */
	snprintf(body, MAXBUF,
	    "<html><title>Proxy Error</title><body bgcolor=""ffffff"">\r\n"
	    "%d: %s\r\n"
	    "<p>%s: %s\r\n"
	    "<hr><em>The COMP 321 Web proxy</em>\r\n",
	    err_num, short_msg, long_msg, truncated_cause);

	/* Build the HTTP response headers. */
	snprintf(headers, MAXBUF,
	    "HTTP/1.0 %d %s\r\n"
	    "Content-type: text/html\r\n"
	    "Content-length: %d\r\n"
	    "\r\n",
	    err_num, short_msg, (int)strlen(body));

	/* Write the HTTP response. */
	if (rio_writen(fd, headers, strlen(headers)) != -1)
		rio_writen(fd, body, strlen(body));
}

import socket
import subprocess
import sys
import time
import uuid
from pathlib import Path

_tests_dir = Path(__file__).resolve().parent.parent / "public"
if str(_tests_dir) not in sys.path:
    sys.path.insert(0, str(_tests_dir))

from fixtures import compile_c_program, make_test_result, USE_DOCKER, DOCKER_IMAGE


def find_free_port() -> int:
    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as sock:
        sock.bind(("", 0))
        sock.listen(1)
        return sock.getsockname()[1]


class DockerProxyProcess:
    def __init__(self, container_name: str):
        self.container_name = container_name

    def poll(self):
        result = subprocess.run(
            ["docker", "inspect", "-f", "{{.State.Running}}", self.container_name],
            capture_output=True,
            text=True,
            timeout=5,
        )
        return None if "true" in result.stdout else 1

    def terminate(self):
        subprocess.run(
            ["docker", "stop", "-t", "2", self.container_name],
            capture_output=True,
            timeout=10,
        )

    def wait(self, timeout=None):
        subprocess.run(
            ["docker", "rm", "-f", self.container_name],
            capture_output=True,
            timeout=timeout or 10,
        )

    def kill(self):
        self.wait(timeout=10)


def start_proxy(workspace: Path, port: int):
    proxy_exe = workspace / "proxy"
    if not proxy_exe.exists():
        success, error = compile_c_program(workspace)
        if not success:
            raise RuntimeError(error)

    if USE_DOCKER:
        container_name = f"proxy-agent-{uuid.uuid4().hex[:8]}"
        result = subprocess.run(
            [
                "docker",
                "run",
                "-d",
                "--name",
                container_name,
                "--memory",
                "4g",
                "--cpus",
                "2",
                "--network=bridge",
                "-p",
                f"{port}:{port}",
                "-v",
                f"{workspace.resolve()}:/workspace",
                "-w",
                "/workspace",
                DOCKER_IMAGE,
                "./proxy",
                str(port),
            ],
            capture_output=True,
            text=True,
            timeout=10,
        )
        if result.returncode != 0:
            raise RuntimeError(result.stderr)
        time.sleep(1.0)
        return DockerProxyProcess(container_name)

    proc = subprocess.Popen(
        [str(proxy_exe), str(port)],
        cwd=str(workspace),
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
    )
    time.sleep(0.5)
    return proc


def send_raw_request(port: int, request: bytes) -> bytes:
    with socket.create_connection(("localhost", port), timeout=10) as sock:
        sock.sendall(request)
        sock.shutdown(socket.SHUT_WR)
        response = b""
        while True:
            chunk = sock.recv(4096)
            if not chunk:
                break
            response += chunk
        return response


def run_error_case(workspace: Path, request: bytes, expected_status: bytes, log_should_exist: bool):
    port = find_free_port()
    proxy_proc = None
    try:
        proxy_proc = start_proxy(workspace, port)
        if proxy_proc.poll() is not None:
            return make_test_result(False, "proxy running", "proxy failed to start", None)

        response = send_raw_request(port, request)
        if expected_status not in response:
            return make_test_result(
                False,
                expected_status.decode(),
                response.decode("utf-8", errors="replace"),
                None,
            )

        time.sleep(0.2)
        log_path = workspace / "proxy.log"
        exists = log_path.exists() and log_path.read_text() != ""
        if exists != log_should_exist:
            return make_test_result(
                False,
                f"log existence == {log_should_exist}",
                f"log existence == {exists}",
                None,
            )

        return make_test_result(True, expected_status.decode(), expected_status.decode(), None)
    finally:
        if proxy_proc:
            proxy_proc.terminate()
            try:
                proxy_proc.wait(timeout=5)
            except subprocess.TimeoutExpired:
                proxy_proc.kill()


def test_rejects_non_get(workspace):
    request = b"POST http://example.com/ HTTP/1.0\r\nHost: example.com\r\n\r\n"
    return run_error_case(workspace, request, b"501 Not Implemented", False)


