+import socket
+import subprocess
+import sys
+import time
+import uuid
+from pathlib import Path
+
+_tests_dir = Path(__file__).resolve().parent.parent / "public"
+if str(_tests_dir) not in sys.path:
+    sys.path.insert(0, str(_tests_dir))
+
+from fixtures import compile_c_program, make_test_result, USE_DOCKER, DOCKER_IMAGE
+
+
+def find_free_port() -> int:
+    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as sock:
+        sock.bind(("", 0))
+        sock.listen(1)
+        return sock.getsockname()[1]
+
+
+class DockerProxyProcess:
+    def __init__(self, container_name: str):
+        self.container_name = container_name
+
+    def poll(self):
+        result = subprocess.run(
+            ["docker", "inspect", "-f", "{{.State.Running}}", self.container_name],
+            capture_output=True,
+            text=True,
+            timeout=5,
+        )
+        return None if "true" in result.stdout else 1
+
+    def terminate(self):
+        subprocess.run(
+            ["docker", "stop", "-t", "2", self.container_name],
+            capture_output=True,
+            timeout=10,
+        )
+
+    def wait(self, timeout=None):
+        subprocess.run(
+            ["docker", "rm", "-f", self.container_name],
+            capture_output=True,
+            timeout=timeout or 10,
+        )
+
+    def kill(self):
+        self.wait(timeout=10)
+
+
+def start_proxy(workspace: Path, port: int):
+    proxy_exe = workspace / "proxy"
+    if not proxy_exe.exists():
+        success, error = compile_c_program(workspace)
+        if not success:
+            raise RuntimeError(error)
+
+    if USE_DOCKER:
+        container_name = f"proxy-agent-{uuid.uuid4().hex[:8]}"
+        result = subprocess.run(
+            [
+                "docker",
+                "run",
+                "-d",
+                "--name",
+                container_name,
+                "--memory",
+                "4g",
+                "--cpus",
+                "2",
+                "--network=bridge",
+                "-p",
+                f"{port}:{port}",
+                "-v",
+                f"{workspace.resolve()}:/workspace",
+                "-w",
+                "/workspace",
+                DOCKER_IMAGE,
+                "./proxy",
+                str(port),
+            ],
+            capture_output=True,
+            text=True,
+            timeout=10,
+        )
+        if result.returncode != 0:
+            raise RuntimeError(result.stderr)
+        time.sleep(1.0)
+        return DockerProxyProcess(container_name)
+
+    proc = subprocess.Popen(
+        [str(proxy_exe), str(port)],
+        cwd=str(workspace),
+        stdout=subprocess.PIPE,
+        stderr=subprocess.PIPE,
+    )
+    time.sleep(0.5)
+    return proc
+
+
+def send_raw_request(port: int, request: bytes) -> bytes:
+    with socket.create_connection(("localhost", port), timeout=10) as sock:
+        sock.sendall(request)
+        sock.shutdown(socket.SHUT_WR)
+        response = b""
+        while True:
+            chunk = sock.recv(4096)
+            if not chunk:
+                break
+            response += chunk
+        return response
+
+
+def run_error_case(workspace: Path, request: bytes, expected_status: bytes, log_should_exist: bool):
+    port = find_free_port()
+    proxy_proc = None
+    try:
+        proxy_proc = start_proxy(workspace, port)
+        if proxy_proc.poll() is not None:
+            return make_test_result(False, "proxy running", "proxy failed to start", None)
+
+        response = send_raw_request(port, request)
+        if expected_status not in response:
+            return make_test_result(
+                False,
+                expected_status.decode(),
+                response.decode("utf-8", errors="replace"),
+                None,
+            )
+
+        time.sleep(0.2)
+        log_path = workspace / "proxy.log"
+        exists = log_path.exists() and log_path.read_text() != ""
+        if exists != log_should_exist:
+            return make_test_result(
+                False,
+                f"log existence == {log_should_exist}",
+                f"log existence == {exists}",
+                None,
+            )
+
+        return make_test_result(True, expected_status.decode(), expected_status.decode(), None)
+    finally:
+        if proxy_proc:
+            proxy_proc.terminate()
+            try:
+                proxy_proc.wait(timeout=5)
+            except subprocess.TimeoutExpired:
+                proxy_proc.kill()
+
+
+def test_rejects_non_get(workspace):
+    request = b"POST http://example.com/ HTTP/1.0\r\nHost: example.com\r\n\r\n"
+    return run_error_case(workspace, request, b"501 Not Implemented", False)
+
+
+def test_requires_host_for_relative_uri(workspace):
+    request = b"GET / HTTP/1.0\r\nUser-Agent: agent-test\r\n\r\n"
+    return run_error_case(workspace, request, b"400 Bad Request", False)
